import React, { useState, useEffect } from "react";
import MapComponent from "./MapComponent";
import BusTrendChart from "./BusTrendChart";

function App() {
  const [showChart, setShowChart] = useState(false);
  const [buses, setBuses] = useState([]);

  // Fetch buses every 2 minutes
  const fetchBuses = async () => {
    try {
      const res = await fetch("http://127.0.0.1:8000/buses");
      const data = await res.json();
      setBuses(data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchBuses(); // initial fetch
    const interval = setInterval(fetchBuses, 120000); // every 2 min
    return () => clearInterval(interval);
  }, []);

  return (
    <div>
      <button
        onClick={() => setShowChart(!showChart)}
        style={{ position: "absolute", top: 10, left: 10, zIndex: 1000 }}
      >
        {showChart ? "Hide Chart" : "Show Chart"}
      </button>

      {showChart && <BusTrendChart buses={buses} />}
      <MapComponent buses={buses} />
    </div>
  );
}

export default App;
